# Unit Tests for `reverse_words`

```python
import pytest
from solution import reverse_words


class TestReverseWordsHappyPath:
    """Tests for normal, expected usage."""

    def test_two_words(self):
        assert reverse_words("hello world") == "world hello"

    def test_three_words(self):
        assert reverse_words("one two three") == "three two one"

    def test_single_word(self):
        assert reverse_words("hello") == "hello"

    def test_sentence_with_punctuation(self):
        assert reverse_words("hello, world!") == "world! hello,"

    def test_words_with_numbers(self):
        assert reverse_words("foo 123 bar") == "bar 123 foo"

    def test_already_reversed(self):
        assert reverse_words("three two one") == "one two three"

    def test_palindrome_sentence(self):
        assert reverse_words("a b a") == "a b a"


class TestReverseWordsEdgeCases:
    """Tests for boundary and unusual inputs."""

    def test_empty_string(self):
        assert reverse_words("") == ""

    def test_single_space(self):
        assert reverse_words(" ") == ""

    def test_multiple_spaces_between_words(self):
        # split() collapses multiple spaces
        assert reverse_words("hello   world") == "world hello"

    def test_leading_spaces(self):
        assert reverse_words("   hello world") == "world hello"

    def test_trailing_spaces(self):
        assert reverse_words("hello world   ") == "world hello"

    def test_leading_and_trailing_spaces(self):
        assert reverse_words("  hello world  ") == "world hello"

    def test_only_spaces(self):
        assert reverse_words("     ") == ""

    def test_single_character_words(self):
        assert reverse_words("a b c d") == "d c b a"

    def test_newline_as_whitespace(self):
        # str.split() treats newlines as whitespace
        assert reverse_words("hello\nworld") == "world hello"

    def test_tab_as_whitespace(self):
        assert reverse_words("hello\tworld") == "world hello"

    def test_mixed_whitespace(self):
        assert reverse_words("hello \t world\n") == "world hello"

    def test_very_long_string(self):
        words = [f"word{i}" for i in range(1000)]
        sentence = " ".join(words)
        expected = " ".join(reversed(words))
        assert reverse_words(sentence) == expected

    def test_unicode_words(self):
        assert reverse_words("café naïve résumé") == "résumé naïve café"

    def test_emoji_words(self):
        assert reverse_words("😀 🎉 🐍") == "🐍 🎉 😀"

    def test_repeated_same_word(self):
        assert reverse_words("spam spam spam") == "spam spam spam"


class TestReverseWordsReturnType:
    """Tests to verify the return type and immutability of input."""

    def test_returns_string(self):
        result = reverse_words("hello world")
        assert isinstance(result, str)

    def test_returns_string_for_empty_input(self):
        result = reverse_words("")
        assert isinstance(result, str)

    def test_original_string_unchanged(self):
        original = "hello world"
        reverse_words(original)
        assert original == "hello world"


class TestReverseWordsErrorCases:
    """Tests for invalid inputs that should raise errors."""

    def test_none_input_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            reverse_words(None)

    def test_integer_input_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            reverse_words
